29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const CURSED_RATE = 0.5;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const HIGH_ENCHANTMENT_RATE = 0.3;
36	
37	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
38	
39	const sumBy = <T>(items: T[], f: (item: T) => number): number =>
40	  items.reduce((sum, item) => sum + f(item), 0);
41	
42	const sumApplicableRates = <T>(rules: Rule<T>[], subject: T): number =>
43	  sumBy(
44	    rules.filter((rule) => rule.applies(subject)),
45	    (rule) => rule.rate,
46	  );
47	
48	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
49	
50	const isCursed = (item: Item): boolean => item.cursed === true;
51	const isHighlyEnchanted = (item: Item): boolean =>
52	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
53	
54	const SURCHARGE_RULES: Rule<Item>[] = [
55	  { applies: isCursed, rate: CURSED_RATE },
56	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
57	];
58	
59	const countByType = (items: Item[]): Map<string, number> => {
60	  const counts = new Map<string, number>();
61	  for (const item of items) {
62	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
63	  }
64	  return counts;
65	};
66	
67	const basePremiumFor = (type: string) => {
68	  const base = BASE_PREMIUM[type];
69	  if (base === undefined) throw new Error(`Unknown item type: ${type}`);
70	  return base;
71	};
72	
73	const premiumForType = (type: string, count: number) => {
74	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
75	    return BLOCK_PREMIUM;
76	  }
77	  return count * basePremiumFor(type);
78	};
79	
80	const surchargeForItem = (item: Item) =>
81	  basePremiumFor(item.type) * sumApplicableRates(SURCHARGE_RULES, item);
82	
83	const policyBasePremium = (items: Item[]) =>
84	  sumBy([...countByType(items)], ([type, count]) => premiumForType(type, count));
85	
86	const totalItemSurcharges = (items: Item[]) => sumBy(items, surchargeForItem);
87	
88	const FIRST_INSURANCE_RATE = 0.1;
89	const LOYALTY_THRESHOLD_YEARS = 2;
90	const LOYALTY_RATE = 0.2;
91	const FOLLOWUP_RATE = 0.15;
92	
93	type QuoteContext = { customer: Customer; stepIndex: number };
94	
95	const CONDITIONAL_ADJUSTMENTS: Rule<QuoteContext>[] = [
96	  {
97	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
98	    rate: -LOYALTY_RATE,
99	  },
100	  { applies: ({ stepIndex }) => stepIndex > 0, rate: -FOLLOWUP_RATE },
101	];
102	
103	const policyAdjustmentRate = (ctx: QuoteContext) =>
104	  FIRST_INSURANCE_RATE + sumApplicableRates(CONDITIONAL_ADJUSTMENTS, ctx);
105	
106	const policyAdjustmentAmount = (policyBase: number, ctx: QuoteContext) =>
107	  policyBase * policyAdjustmentRate(ctx);
108	
109	const quote = (items: Item[], customer: Customer, stepIndex: number) => {
110	  const policyBase = policyBasePremium(items);
111	  const premium =
112	    policyBase +
113	    policyAdjustmentAmount(policyBase, { customer, stepIndex }) +
114	    totalItemSurcharges(items);
115	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
116	};
117	
118	const INSURANCE_VALUE_MULTIPLIER = 10;
119	const DEDUCTIBLE = 100;
120	const CAP_MULTIPLIER = 2;
121	
122	const insuranceValueFor = (type: string) =>
123	  basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
124	
125	const insuranceSum = (items: Item[]) =>
126	  sumBy(items, (item) => insuranceValueFor(item.type));
127	
128	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
129	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
130	
131	const reimbursableDamage = (item: Item, damage: Damage) =>
132	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
133	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
134	    : damage.amount;
135	
136	const payoutForDamage = (item: Item, damage: Damage) =>
137	  Math.max(0, reimbursableDamage(item, damage) - DEDUCTIBLE);
138	
139	type PolicyState = { items: Item[]; remainingCap: number };
140	
141	const consumeItem = (available: Item[], itemType: string): Item => {
142	  const idx = available.findIndex((i) => i.type === itemType);
143	  if (idx === -1) throw new Error(`No insured ${itemType} in policy`);
144	  return available.splice(idx, 1)[0];
145	};
146	
147	const totalPayout = (items: Item[], damages: Damage[]) => {
148	  const available = [...items];
149	  return sumBy(damages, (damage) =>
150	    payoutForDamage(consumeItem(available, damage.itemType), damage),
151	  );
152	};
153	
154	const newPolicy = (items: Item[]): PolicyState => ({
155	  items,
156	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
157	});
158	
159	const claim = (policy: PolicyState, damages: Damage[]) => {
160	  const payout = Math.min(totalPayout(policy.items, damages), policy.remainingCap);
161	  policy.remainingCap -= payout;
162	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
163	};
